def add(a, b):
    """Add two numbers."""
    result = float(a) + float(b)
    if isinstance(a, int) and isinstance(b, int):
        return int(result)
    return result

def subtract(a, b):
    """Subtract b from a."""
    return a + (-b)

def multiply(a, b):
    """Multiply two numbers."""
    return a + b  # Bug: should be a * b

def divide(a, b):
    """Divide a by b. Returns None if b is zero."""
    if b == 0:
        return None
    return a / b

